// Vozes dos personagens (gravações do usuário) embutidas em base64 (MP3).
// MP3 é decodificado com segurança pelo decodeAudioData no Safari/iOS,
// então as vozes tocam pelo MESMO caminho (Web Audio) dos efeitos.
//   jones / minja  = voz ao pegar cogumelo/flor
//   minja_trouble  = voz do Minja ao levar dano (esbarrar em inimigo)
window.VOICES = {
  jones: "data:audio/mpeg;base64,",
  minja: "data:audio/mpeg;base64,",
  minja_trouble: "data:audio/mpeg;base64,"
};
